// config.js - Minified configuration
const CONFIG={API_BASE_URL:'http://127.0.0.1:8000',API_ENDPOINTS:{REGISTER:'/auth/users/',ACTIVATION:'/auth/users/activation/',LOGIN:'/auth/jwt/create/',REFRESH:'/auth/jwt/refresh/',VERIFY:'/auth/jwt/verify/',USER_DETAILS:'/auth/users/me/',USER_UPDATE:'/auth/users/me/',ADVISOR_ASK:'/advisor/ask/',ADVISOR_HISTORY:'/advisor/history/'},STORAGE_KEYS:{ACCESS_TOKEN:'access_token',REFRESH_TOKEN:'refresh_token',USER_DATA:'user_data'}};function getAccessToken(){return localStorage.getItem(CONFIG.STORAGE_KEYS.ACCESS_TOKEN)}function setTokens(e,t){localStorage.setItem(CONFIG.STORAGE_KEYS.ACCESS_TOKEN,e),localStorage.setItem(CONFIG.STORAGE_KEYS.REFRESH_TOKEN,t)}function clearTokens(){localStorage.removeItem(CONFIG.STORAGE_KEYS.ACCESS_TOKEN),localStorage.removeItem(CONFIG.STORAGE_KEYS.REFRESH_TOKEN),localStorage.removeItem(CONFIG.STORAGE_KEYS.USER_DATA)}function isAuthenticated(){return null!==getAccessToken()}
